  ('elementary-f29af906-moex-00972', 'elementary-f29af906', 'elementary-f29af906-moex-110-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '下列何者情形，原行政處分效力之喪失，不需由行政機關再行作出行政處分？', '["經取得開發許可之申請人違反原許可之土地使用計畫時", "附負擔之授益處分，處分相對人未履行負擔時", "徵收處分因作業錯誤，致原徵收土地不在工程用地範圍內時", "土地徵收公告後，直轄市、縣（市）主管機關未於徵收公告期滿15日內發放補償費時"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:56+00:00", "source_pdf_sha1": "753edbff8c70", "answer_pdf_sha1": "09eb751b23b0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
