  ('elementary-f29af906-moex-00974', 'elementary-f29af906', 'elementary-f29af906-moex-110-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '依平均地權條例規定，土地所有權移轉時，權利人及義務人應於買賣案件辦竣移轉登記30日內，向主管 機關申報登錄土地及建物成交案件實際資訊；主管機關對於違反規定者，應為下列何種處分？', '["罰鍰", "罰金", "怠金", "禁止登記"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:56+00:00", "source_pdf_sha1": "753edbff8c70", "answer_pdf_sha1": "09eb751b23b0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00975', 'elementary-f29af906', 'elementary-f29af906-moex-110-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '行政機關對於行政處分所依據之事實或法律關係，經依職權調查仍不能確定者，為有效達成行政目的， 並解決爭執，得採取下列何種行為，以代替行政處分？', '["採取行政指導", "應用行政規則", "研訂法規命令", "締結行政契約"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:56+00:00", "source_pdf_sha1": "753edbff8c70", "answer_pdf_sha1": "09eb751b23b0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00976', 'elementary-f29af906', 'elementary-f29af906-moex-110-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '下列何種情形，不需給予人民補償或賠償？', '["受益人有信賴值得保護之情形，經處分機關撤銷違法授益行政處分", "附負擔之授益處分，因未履行負擔，經處分機關廢止該授益行政處分者", "在有情事變遷時，行政機關為維護公益，命締結行政契約之人民繼續履行原約定義務", "原處分雖違法，但其撤銷於公益有重大損害，經行政法院以情況判決駁回原告之訴者"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:56+00:00", "source_pdf_sha1": "753edbff8c70", "answer_pdf_sha1": "09eb751b23b0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('generalpolice-0395e56f-moex-00001', 'generalpolice-0395e56f', 'generalpolice-0395e56f-moex-114-de0a21a2', 'sub-generalpolice-0395e56f-01', NULL, 'essay', '公務員甲因投資失敗，欠下鉅額債務，某日知悉經營貴金屬鑑定的好友
乙，正好於家中保管客戶 A的高價金屬，甲告訴乙，該貴金屬依照 A的
經營模式一定有保險，不如想出一個方法，對 A謊稱該批貴金屬遭人搶
劫，實際上由甲變賣，利益兩人均分，對 A來說也不會有太多損失。乙
告訴甲，可以將該批貴金屬拿一些出來，客戶應該不會發現，但謊稱整
批被搶走，很難說得過去。兩人商議後，同意由乙取出部分貴金屬（市
價約新臺幣 200萬元）藉由甲的人脈關係賣出，獲取金額由乙拿六成，
甲拿四成。因為在交易市場中，買家丙私下辨識出該貴金屬為 A所有，
且甲無法交代貴金屬來源，實際賣得總價只有 50萬，甲、乙依兩人約定
朋分贓款。
數月後甲仍需錢孔急，甲到乙的辦公室向乙借錢，稱討債公司揚言，若
不還錢，將加害甲的家人。乙考慮數日後，仍拒絕借錢給甲。另一方面，
乙心中確實不忍甲的家人遭受危難，乙將甲約至辦公室，對甲婉轉說明
自己手上也沒有多餘現金可供週轉，無法借錢給甲。乙以有要事處理為
由要外出一趟，離開辦公室前將家中存放貴金屬之保險箱的鑰匙放置桌
上，心想如果甲識得該鑰匙並且能夠使用鑰匙拿走貴金屬，也算幫甲一
個忙。甲果然認得該鑰匙為乙家中保險箱鑰匙，趁辦公室四下無人，甲
將鑰匙放進口袋後即離開。當天夜裡，甲攜帶鑰匙潛入乙的家中，開啟
保險箱並將裡面所存放之 A的貴金屬一掃而空。試問甲、乙的行為依刑
法如何評價？（50 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:49+00:00", "source_pdf_sha1": "a91534b7814d", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "304", "s": "0604", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法與刑事訴訟法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "警察資訊管理人員"}'::jsonb, NULL)
